              border: "1px solid #333",
              borderRadius: 6,
              color: "#e0e0e0",
              fontSize: "0.8rem",
            }}
          />
          <button onClick={joinRoom} style={btnStyle("#6b21a8")}>
            Join
          </button>
        </div>

        {/* Session controls */}
        <div style={{ display: "flex", gap: 8 }}>
